            bot: bot.clone(),
            bot_username: Some("test_bot".into()),
            account_id: account_id.to_string(),
            config: TelegramAccountConfig {
                token: Secret::new("test-token".to_string()),
                dm_policy: DmPolicy::Open,
                ..Default::default()
            },
